/**
 * Belirtilen HTML canvas elementi üzerine bir dikey çubuk grafik oluşturur.
 *
 * @param {string} canvasId - Grafiğin çizileceği HTML canvas elementinin ID'si.
 * @param {object} chartData - Grafik verilerini içeren nesne. Format:
 *   {
 *     "labels": ["Ocak", "Subat", "Mart", "Nisan", "Mayis", "Haziran"],
 *     "datasets": [
 *       {
 *         "label": "Satışlar",
 *         "data": [12, 19, 3, 5, 2, 3],
 *         "backgroundColor": "rgba(75, 192, 192, 0.6)",
 *         "borderColor": "rgba(75, 192, 192, 1)",
 *         "borderWidth": 1
 *       }
 *     ]
 *   }
 * @param {object} [chartOptions] - Chart.js özelleştirme seçeneklerini içeren nesne (opsiyonel).
 * @returns {Chart|null} Oluşturulan Chart.js grafik nesnesi veya hata durumunda null.
 */
function setupBarChart(canvasId, chartData, chartOptions) {
  const ctx = document.getElementById(canvasId);
  if (!ctx) {
    console.error(`Canvas element with ID '${canvasId}' not found.`);
    return null;
  }

  // Varsayılan seçenekler, eğer belirtilmemişse
  const defaultOptions = {
    scales: {
      y: {
        beginAtZero: true
      }
    }
  };

  // Kullanıcı tarafından sağlanan seçenekleri varsayılanlarla birleştir
  const finalOptions = {
    ...defaultOptions,
    ...chartOptions
  };

  try {
    const myChart = new Chart(ctx, {
      type: 'bar',
      data: chartData,
      options: finalOptions
    });
    return myChart;
  } catch (error) {
    console.error('Error creating chart:', error);
    return null;
  }
}

// Not: Bu kodun çalışması için Chart.js kütüphanesinin HTML'e dahil edilmesi gerekmektedir.
// Örneğin, <script src="https://cdn.jsdelivr.net/npm/chart.js"></script> şeklinde.
// Ayrıca, grafiğin çizileceği <canvas id="myCanvas"></canvas> elementi HTML'de bulunmalıdır.

const takilar = [
  { id: 1, ad: "Altın Kolye", puan: 95 },
  { id: 2, ad: "Gümüş Bileklik", puan: 88 },
  { id: 3, ad: "Elmas Yüzük", puan: 98 },
  { id: 4, ad: "Zümrüt Küpe", puan: 92 },
  { id: 5, ad: "Safir Kolye Ucu", puan: 90 }
];

// Bu veri yapısı, ön uçta (frontend) kullanılmak üzere tasarlanmıştır.
// Örnek kullanım:
// takilar.forEach(taki => {
//   console.log(`Takı Adı: ${taki.ad}, Puanı: ${taki.puan}`);
// });

/**
 * Verilen verileri kullanarak dikey çubuk grafik oluşturan bir fonksiyon.
 * Varsayılan olarak Chart.js kütüphanesi kullanılır.
 *
 * @param {Array<Object>} veri - Grafikte gösterilecek verileri içeren bir dizi.
 *   Her nesne en azından bir 'etiket' (string) ve bir 'değer' (number) içermelidir.
 *   Örnek: [{ etiket: 'Ocak', deger: 150 }, { etiket: 'Subat', deger: 220 }]
 * @param {string} grafikKonteyneriId - Grafiğin çizileceği HTML elementinin ID'si.
 */
function olusturDikeyCubukGrafik(veri, grafikKonteyneriId) {
  // Grafik konteynerini DOM'dan al
  const konteyner = document.getElementById(grafikKonteyneriId);

  // Konteyner bulunamazsa veya veri yoksa işlem yapma
  if (!konteyner || !veri || veri.length === 0) {
    console.error("Grafik konteyneri bulunamadı veya geçersiz veri sağlandı.");
    return;
  }

  // Chart.js için verileri uygun formata dönüştür
  const etiketler = veri.map(item => item.etiket);
  const degerler = veri.map(item => item.deger);

  // Mevcut bir grafik varsa temizle
  // Bu, fonksiyonun tekrar tekrar çağrılması durumunda eski grafiğin üzerine yazılmasını sağlar.
  if (konteyner.chart) {
    konteyner.chart.destroy();
  }

  // Chart.js ile yeni grafik oluştur
  const ctx = konteyner.getContext('2d');
  konteyner.chart = new Chart(ctx, {
    type: 'bar', // Grafik türü: dikey çubuk
    data: {
      labels: etiketler,
      datasets: [{
        label: 'Değerler',
        data: degerler,
        backgroundColor: 'rgba(75, 192, 192, 0.6)', // Çubukların arka plan rengi
        borderColor: 'rgba(75, 192, 192, 1)', // Çubukların kenarlık rengi
        borderWidth: 1
      }]
    },
    options: {
      responsive: true, // Grafiğin kapsayıcısına duyarlı olmasını sağlar
      maintainAspectRatio: false, // Grafiğin en boy oranını korumasını engeller (yükseklik ayarı için)
      scales: {
        y: {
          beginAtZero: true // Y ekseninin sıfırdan başlamasını sağlar
        }
      }
    }
  });
}

